{'Duration(milliseconds': 500, 'padding': 'const EdgeInsets.all(16)', 'decoration': 'BoxDecoration(\n        color: Colors.white', 'borderRadius': 'BorderRadius.circular(16)', 'boxShadow': ["BoxShadow(\n            color: Colors.black.withValues(alpha: 0.05),\n            blurRadius: 8,\n            offset: const Offset(0, 2),\n          ),\n        ],\n      ),\n      child: Column(\n        crossAxisAlignment: CrossAxisAlignment.start,\n        children: [\n          Row(\n            children: [\n              const Icon(Icons.trending_up, size: 18, color: AppColors.primary),\n              const SizedBox(width: 8),\n              Text(\n                '7-Day Forecast',\n                style: const TextStyle(\n                  fontSize: 16,\n                  fontWeight: FontWeight.bold,\n                  color: AppColors.textPrimary,\n                ),\n              ),\n            ],\n          ),\n          const SizedBox(height: 16),\n          SizedBox(\n            height: 180,\n            child: _loading\n                ? const Center(child: CircularProgressIndicator(color: AppColors.primary))\n                : _spots.isEmpty\n                ? const Center(child: Text('No forecast data available'))\n                : LineChart(\n                    LineChartData(\n                      gridData: FlGridData(\n                        show: true,\n                        drawVerticalLine: false,\n                        horizontalInterval: 5,\n                        getDrawingHorizontalLine: (value) => FlLine(\n                          color: Colors.grey.shade200,\n                          strokeWidth: 1,\n                        ),\n                      ),\n                      titlesData: FlTitlesData(\n                        show: true,\n                        bottomTitles: AxisTitles(\n                          sideTitles: SideTitles(\n                            showTitles: true,\n                            interval: 1,\n                            getTitlesWidget: (value, meta) {\n                              final days = ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'];\n                              final index = value.toInt();\n                              if (index >= 0 && index < days.length) {\n                                return Text(\n                                  days[index],\n                                  style: const TextStyle(fontSize: 10, color: AppColors.textSecondary),\n                                );\n                              }\n                              return const Text('');\n                            },\n                          ),\n                        ),\n                        leftTitles: AxisTitles(\n                          sideTitles: SideTitles(\n                            showTitles: true,\n                            reservedSize: 30,\n                            getTitlesWidget: (value, meta) => Text(\n                              value.toInt().toString(),\n                              style: const TextStyle(fontSize: 10, color: AppColors.textSecondary),\n                            ),\n                          ),\n                        ),\n                        rightTitles: const AxisTitles(sideTitles: SideTitles(showTitles: false)),\n                        topTitles: const AxisTitles(sideTitles: SideTitles(showTitles: false)),\n                      ),\n                      borderData: FlBorderData(show: false),\n                      lineBarsData: [\n                        LineChartBarData(\n                          spots: _spots,\n                          isCurved: true,\n                          color: AppColors.primary,\n                          barWidth: 3,\n                          dotData: FlDotData(\n                            show: true,\n                            getDotPainter: (spot, percent, barData, index) => FlDotCirclePainter(\n                              radius: 4,\n                              color: AppColors.primary,\n                              strokeWidth: 2,\n                              strokeColor: Colors.white,\n                            ),\n                          ),\n                          belowBarData: BarAreaData(\n                            show: true,\n                            color: AppColors.primary.withValues(alpha: 0.1),\n                          ),\n                        ),\n                      ],\n                    ),\n                  ),\n          ),\n        ],\n      ),\n    );\n  }\n}"]}